#include<bits/stdc++.h>
using namespace std;
long long n,v,m,p[510],q[510],f[21][1000010],sum[21];
bool flag[1000010],t[31];
constexpr long long mod=1e9+7;
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
int main()
{
    scanf("%lld%lld%lld",&n,&v,&m);
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld%lld",&p[i],&q[i]);
        p[i]--;
        q[i]--;
    }
    for(long long i=0;i<(1<<n);i++)
    {
        for(long long j=0;j<n;j++)
        {
            t[j]=((i>>j)&1);
        }
        for(long long j=1;j<=m;j++)
        {
            if(t[p[j]]>t[q[j]])
            {
                swap(t[p[j]],t[q[j]]);
            }
        }
        flag[i]=true;
        for(long long j=1;j<n;j++)
        {
            if(t[j-1]>t[j])
            {
                flag[i]=false;
            }
        }
    }
    f[0][0]=1;
    for(long long i=1;i<=n;i++)
    {
        memcpy(f[i],f[i-1],sizeof(f[i-1]));
        for(long long j=0;j<n;j++)
        {
            for(long long k=0;k<(1<<n);k++)
            {
                if(!((k>>j)&1))
                {
                    f[i][k|(1<<j)]+=f[i][k];
                    f[i][k|(1<<j)]%=mod;
                }
            }
        }
        for(long long j=0;j<(1<<n);j++)
        {
            if(!flag[j])
            {
                f[i][j]=0;
            }
        }
    }
    for(long long i=0;i<=n;i++)
    {
        for(long long j=0;j<(1<<n);j++)
        {
            sum[i+1]+=f[i][j];
            sum[i+1]%=mod;
        }
    }
    long long ans=0;
    for(long long i=1;i<=n+1;i++)
    {
        long long s=1;
        for(long long j=1;j<=n+1;j++)
        {
            if(j!=i)
            {
                s=s*fastpow(((i-j)%mod+mod)%mod,mod-2)%mod;
            }
        }
        for(long long j=1;j<=n+1;j++)
        {
            if(j!=i)
            {
                s=s*((v-j)%mod+mod)%mod;
            }
        }
        ans=(ans+s*sum[i]%mod)%mod;
    }
    printf("%lld",ans);
    return 0;
}
